import pg from "pg";
import crypto from "crypto";
const Pool = pg.Pool;
const pool = new Pool({ connectionString: process.env.PROD_DATABASE_URL || process.env.DATABASE_URL });
function hash(s: string): string { return crypto.createHash("md5").update(s.toLowerCase().trim()).digest("hex"); }
function rn(e:string,b:string,d:number,s:string,o:string[],c:number,r:string) {
  return {tier:"rn",exam:e,stem:s,options:o,correct:c,rationale:r,diff:d,bs:b};
}
function np(e:string,b:string,d:number,s:string,o:string[],c:number,r:string) {
  return {tier:"np",exam:e,stem:s,options:o,correct:c,rationale:r,diff:d,bs:b};
}
function rpn(e:string,b:string,d:number,s:string,o:string[],c:number,r:string) {
  return {tier:"rpn",exam:e,stem:s,options:o,correct:c,rationale:r,diff:d,bs:b};
}

const QS = [
  // === RN (100 - targets 305 more needed) ===
  rn("NCLEX-RN","Cardiovascular",3,"A client with a mechanical prosthetic valve requires lifelong anticoagulation with warfarin because:",["Tissue valves are always used instead","Mechanical valves are highly thrombogenic due to their non-biological surface","Aspirin is sufficient for mechanical valves","No anticoagulation is needed after 6 months"],1,"Mechanical valves require lifelong warfarin (INR 2.5-3.5 depending on valve position and risk factors). DOACs are contraindicated for mechanical valves (RE-ALIGN trial showed increased events with dabigatran). Aspirin is added for high-risk patients."),
  rn("NCLEX-RN","Cardiovascular",3,"A client with Marfan syndrome should avoid which activity?",["Walking and swimming","Heavy isometric exercise and contact sports (risk of aortic dissection/rupture)","Light aerobic exercise","All physical activity permanently"],1,"Marfan syndrome affects fibrillin-1, weakening connective tissue including the aorta. Heavy lifting, isometric exercise, and contact sports increase aortic wall stress and dissection risk. Regular echocardiographic monitoring of aortic root diameter. Beta-blockers and losartan reduce aortic dilation rate."),
  rn("RN-CAT","Cardiovascular",4,"A client with cardiorenal syndrome type 1 develops worsening renal function during acute heart failure decompensation. Management includes:",["Stopping all diuretics to protect the kidneys","Continuing diuretics to decongest while monitoring renal function; ultrafiltration if diuretic-resistant","Aggressive IV fluid resuscitation","Renal transplant evaluation"],1,"Cardiorenal syndrome type 1: acute HF worsening leading to AKI. Congestion (elevated CVP) is the primary driver of renal dysfunction, not low cardiac output. Continue diuretics for decongestion even if creatinine rises modestly. Ultrafiltration for diuretic-resistant fluid overload."),
  rn("NCLEX-RN","Cardiovascular",3,"A client with atrial septal defect has a fixed split S2 on auscultation. This finding results from:",["Aortic valve disease","Constant RV volume overload causing delayed pulmonic valve closure regardless of respiration","Left-sided heart failure","Mitral regurgitation"],1,"Fixed split S2: pathognomonic for ASD. The left-to-right shunt causes constant RV volume overload, delaying pulmonic valve closure. Unlike physiological splitting (varies with respiration), the split is fixed because RV filling remains constant regardless of respiratory phase."),
  rn("NCLEX-RN","Respiratory",3,"A client with pneumocystis pneumonia (PCP) has bilateral ground-glass opacities on CT. The nurse should anticipate:",["Oral antibiotics only","High-dose TMP-SMX and corticosteroids if PaO2 < 70 mmHg","Antifungal therapy","No treatment as it resolves spontaneously"],1,"PCP treatment: TMP-SMX (first-line, 21 days for HIV, 14 for non-HIV). Add prednisone if PaO2 < 70 or A-a gradient > 35 (reduces mortality by decreasing inflammatory-mediated lung injury). PCP prophylaxis (TMP-SMX) for HIV patients with CD4 < 200."),
  rn("NCLEX-RN","Respiratory",3,"A client with acute chest syndrome in sickle cell disease should receive:",["Only IV fluids and pain management","Exchange transfusion, supplemental oxygen, IV antibiotics, and pain management","Increased hydration without other treatment","Oral antibiotics only"],1,"ACS (new pulmonary infiltrate + respiratory symptoms in SCD) management: simple or exchange transfusion (target Hgb S < 30%), supplemental oxygen, empiric broad-spectrum antibiotics (ceftriaxone + macrolide), pain management, incentive spirometry, and bronchodilators."),
  rn("NCLEX-RN","Respiratory",3,"A client with chylothorax has milky pleural fluid with elevated triglycerides. The nurse should understand:",["This is a simple pleural effusion","Chylothorax results from thoracic duct disruption with lymphatic fluid (chyle) accumulating in the pleural space","The fluid is purulent and requires antibiotics","No intervention is needed"],1,"Chylothorax: thoracic duct leak (trauma, surgery, malignancy) causes chylous effusion. Milky fluid with triglycerides > 110 mg/dL confirms diagnosis. Management: chest drainage, NPO or medium-chain triglyceride diet (absorbed directly into portal vein), octreotide, and surgical repair if conservative fails."),
  rn("NCLEX-RN","Neurological",3,"A client with wernicke encephalopathy presents with the classic triad. The nurse should administer:",["Glucose solution immediately","IV thiamine BEFORE any glucose administration","Oral vitamins only","IV glucose without thiamine"],1,"Wernicke triad: confusion, ataxia, ophthalmoplegia. Thiamine (vitamin B1) must be given BEFORE glucose because glucose metabolism consumes thiamine and can precipitate or worsen Wernicke encephalopathy. IV thiamine 500mg TID for 2-3 days, then daily."),
  rn("NCLEX-RN","Neurological",3,"A client with locked-in syndrome after a basilar artery stroke is:",["Unconscious and unaware","Fully conscious and aware but unable to move or speak, communicating only through eye movements","In a persistent vegetative state","Brain dead"],1,"Locked-in syndrome: ventral pons damage (basilar artery occlusion) destroys all motor pathways while preserving consciousness and cognition. Client is fully aware but can only communicate through vertical eye movements and blinking. Not to be confused with coma or vegetative state."),
  rn("NCLEX-RN","Neurological",3,"A client with complex regional pain syndrome (CRPS) has burning pain, allodynia, and trophic changes in the affected limb. Treatment includes:",["Amputation of the affected limb","Multidisciplinary approach: physical therapy, mirror therapy, sympathetic nerve blocks, and neuropathic pain medications","Opioids as sole treatment","Immobilization of the affected limb"],1,"CRPS requires multidisciplinary treatment: physical therapy (crucial, prevents contractures), mirror therapy, neuropathic pain medications (gabapentin, duloxetine), sympathetic nerve blocks, bisphosphonates, psychological support, and spinal cord stimulation for refractory cases. Immobilization worsens the condition."),
  rn("NCLEX-RN","Endocrine",3,"A client with diabetes insipidus demonstrates water deprivation test results showing no concentration of urine despite elevated serum osmolality. After administering DDAVP, the urine concentrates. This confirms:",["Nephrogenic DI","Central DI (the kidney responds to exogenous ADH, confirming the problem is insufficient ADH production)","Psychogenic polydipsia","Normal findings"],1,"Water deprivation test differentiates DI types: central DI = urine concentrates after DDAVP (functioning kidney, deficient ADH production), nephrogenic DI = urine does NOT concentrate after DDAVP (kidney resistant to ADH), psychogenic polydipsia = urine concentrates with water deprivation alone."),
  rn("NCLEX-RN","Endocrine",3,"A client with autoimmune polyglandular syndrome type 2 (Schmidt syndrome) has both Addison disease and autoimmune thyroiditis. The nurse should:",["Treat hypothyroidism first","Replace cortisol (hydrocortisone) BEFORE starting levothyroxine to prevent adrenal crisis","Start both medications simultaneously","Treat neither condition"],1,"In APS-2 with both adrenal insufficiency and hypothyroidism: ALWAYS replace cortisol first. Starting levothyroxine without cortisol replacement increases cortisol metabolism, potentially precipitating life-threatening adrenal crisis. Stabilize cortisol replacement, then add levothyroxine."),
  rn("NCLEX-RN","Gastrointestinal",3,"A client with gastroparesis from diabetes should be managed with:",["Large meals to ensure adequate nutrition","Small frequent low-fat, low-fiber meals, prokinetics (metoclopramide), and optimization of blood glucose","High-fat diet for caloric density","Fasting to rest the stomach"],1,"Diabetic gastroparesis: small frequent meals (4-6/day), low fat (fat delays emptying), low fiber (bezoar risk), chew thoroughly, walk after eating. Pharmacotherapy: metoclopramide (dopamine antagonist - risk of tardive dyskinesia), erythromycin (motilin agonist, tachyphylaxis). Glucose optimization improves gastric motility."),
  rn("NCLEX-RN","Gastrointestinal",3,"A client with colonic diverticulitis without perforation should be managed with:",["Immediate colectomy","Antibiotics (metronidazole + fluoroquinolone or amoxicillin-clavulanate), clear liquid diet, and pain management","High-fiber diet during acute episode","No treatment needed"],1,"Uncomplicated diverticulitis: antibiotics (controversial in mild cases; selective antibiotic use is emerging), clear liquids progressing to low-fiber then high-fiber diet, pain management (avoid opioids if possible). CT scan confirms diagnosis and rules out complications. Surgery for complicated or recurrent disease."),
  rn("NCLEX-RN","Pharmacology",3,"A client being started on a new antidepressant should be warned that the FDA black box warning for SSRIs states:",["SSRIs cause addiction","Increased risk of suicidal thinking and behavior in children, adolescents, and young adults (up to age 24)","SSRIs always cause sexual dysfunction","No significant warnings exist"],1,"FDA black box warning: SSRIs and all antidepressants may increase suicidal ideation in patients under 25 during the initial weeks of treatment. Monitor closely during first 1-2 months and dose changes. The benefit-risk ratio still favors treatment for depression in most patients."),
  rn("NCLEX-RN","Pharmacology",3,"A client prescribed potassium supplementation should take the oral formulation:",["On an empty stomach for better absorption","With food and a full glass of water to reduce GI irritation","At bedtime on an empty stomach","Chewed rather than swallowed whole"],1,"Oral KCl can cause severe GI irritation, ulceration, and even perforation if taken without food. Take with meals and 8 oz water. Extended-release formulations reduce GI irritation. Avoid lying down for 30 minutes after taking. Monitor serum potassium levels."),
  rn("NCLEX-RN","Pharmacology",3,"A client receiving IV vasopressin for gastrointestinal bleeding should be monitored for:",["Only GI effects","Cardiac ischemia (vasopressin causes coronary vasoconstriction)","Hypoglycemia","Respiratory depression"],1,"IV vasopressin for GI bleeding (splanchnic vasoconstriction) also causes coronary vasoconstriction, potentially precipitating myocardial ischemia/infarction. Concurrent IV nitroglycerin reduces coronary vasoconstriction risk. Monitor ECG, chest pain, and hemodynamic status continuously."),
  rn("NCLEX-RN","Mental Health",3,"A client with acute alcohol intoxication and a BAC of 0.40% is at risk for:",["Only mild sedation","Respiratory depression, aspiration, and death","Improved coordination","Enhanced judgment"],1,"BAC 0.30-0.40%: severe impairment, stupor, loss of consciousness, risk of aspiration. BAC > 0.40%: respiratory depression, cardiovascular collapse, and death. Management: protect airway, lateral positioning (prevent aspiration), IV thiamine, glucose monitoring, and close observation."),
  rn("NCLEX-RN","Mental Health",3,"A client with anorexia nervosa being refed after significant malnutrition should be monitored for refeeding syndrome. The key electrolyte to monitor is:",["Sodium","Phosphorus (hypophosphatemia is the hallmark of refeeding syndrome)","Calcium","Chloride"],1,"Refeeding syndrome: insulin surge from carbohydrate reintroduction drives phosphorus, potassium, and magnesium into cells. Severe hypophosphatemia can cause cardiac failure, respiratory failure, rhabdomyolysis, and death. Start feeding slowly (10-20 kcal/kg/day), supplement phosphorus, and monitor electrolytes daily."),
  rn("NCLEX-RN","Pediatrics",3,"A child with acute glomerulonephritis post-streptococcal infection presents with:",["Polyuria and weight loss","Periorbital edema (especially upon waking), hematuria (tea/cola-colored urine), hypertension, and oliguria","Clear urine and no edema","Increased appetite"],1,"PSGN: develops 1-3 weeks after GAS pharyngitis or 3-6 weeks after skin infection. Features: periorbital/facial edema (worst in morning), hematuria (smoky/cola urine), hypertension, and oliguria. Self-limited in children (> 95% recover completely). Monitor BP, fluid balance, and renal function."),
  rn("NCLEX-RN","Pediatrics",3,"A child with scoliosis and a Cobb angle of 30 degrees should be managed with:",["No treatment needed","Bracing (Boston brace or Rigo-Cheneau brace) to prevent curve progression","Immediate surgical fusion","Physical therapy alone"],1,"Scoliosis management by Cobb angle: < 25 degrees = observation, 25-40 degrees in growing child = bracing (worn 16-23 hours/day until skeletal maturity), > 40-50 degrees = surgical spinal fusion. BrAIST study confirmed bracing significantly reduces curve progression. Exercise and PT complement bracing."),
  rn("NCLEX-RN","Pediatrics",3,"A premature infant develops necrotizing enterocolitis. The nurse should observe for:",["Normal feeding tolerance","Abdominal distension, bloody stools, feeding intolerance, and pneumatosis intestinalis on X-ray","Improved weight gain","Increased appetite"],1,"NEC signs: feeding intolerance, abdominal distension, bloody stools, temperature instability, lethargy. X-ray: pneumatosis intestinalis (air in bowel wall - pathognomonic), portal venous gas, pneumoperitoneum (perforation). Management: NPO, NG decompression, IV antibiotics, TPN. Surgery for perforation or failure to improve."),
  rn("NCLEX-RN","Maternal/Newborn",3,"A client with a Bishop score of 3 who requires induction should have:",["Immediate oxytocin infusion","Cervical ripening with prostaglandins (misoprostol or dinoprostone) before oxytocin","Cesarean delivery without attempting induction","Membrane stripping only"],1,"Bishop score < 6 indicates an unfavorable cervix. Cervical ripening improves induction success. Options: PGE2 (dinoprostone gel or insert), misoprostol (PGE1, oral or vaginal), or mechanical (Foley bulb, Cook balloon). After cervical ripening, oxytocin induction follows. Misoprostol is contraindicated in prior cesarean."),
  rn("NCLEX-RN","Maternal/Newborn",3,"A client with severe preeclampsia and HELLP syndrome has:",["Normal liver function","Hemolysis (elevated LDH, schistocytes), Elevated Liver enzymes, and Low Platelets","Only elevated blood pressure","Normal platelet count"],1,"HELLP syndrome: Hemolysis (elevated LDH, haptoglobin low, schistocytes on smear), Elevated Liver enzymes (AST/ALT), Low Platelets (< 100,000). Associated with high maternal morbidity/mortality. Treatment: magnesium sulfate, blood pressure management, and delivery (definitive treatment)."),
  rn("NCLEX-RN","Renal",3,"A client with thrombotic microangiopathy (atypical HUS) presents with complement-mediated hemolytic anemia, thrombocytopenia, and renal failure. Treatment includes:",["Plasma exchange alone","Eculizumab (complement C5 inhibitor) for atypical HUS","Antibiotics","No specific treatment exists"],1,"Atypical HUS: complement-mediated TMA distinct from STEC-HUS. Eculizumab blocks terminal complement activation, dramatically improving outcomes. Meningococcal vaccination is required before starting (blocks C5, increasing Neisseria meningitidis risk). May require lifelong treatment."),
  rn("NCLEX-RN","Infection Control",3,"A client with carbapenem-resistant Enterobacteriaceae (CRE) requires:",["Standard precautions only","Enhanced contact precautions, dedicated equipment, and antimicrobial stewardship","Airborne precautions","No special precautions"],1,"CRE: extensively drug-resistant organisms requiring enhanced contact precautions (gown, gloves, dedicated equipment), single room (ideally), enhanced environmental cleaning, and antimicrobial stewardship. Treatment options limited: ceftazidime-avibactam, meropenem-vaborbactam, or combination therapy."),
  rn("NCLEX-RN","Hematological",3,"A client with acquired hemophilia A (inhibitor development) has sudden spontaneous bleeding without personal or family history. Treatment includes:",["Factor VIII replacement only (will be ineffective due to inhibitor)","Bypassing agents (rFVIIa or activated PCC) and immunosuppressive therapy to eliminate the inhibitor","Desmopressin alone","Platelet transfusion"],1,"Acquired hemophilia A: autoantibodies against factor VIII. Factor replacement is ineffective when inhibitor titer is high. Bypassing agents (rFVIIa, FEIBA) provide hemostasis. Immunosuppression (steroids +/- cyclophosphamide or rituximab) eliminates the inhibitor. Most cases resolve with treatment."),
  rn("NCLEX-RN","Immunological",3,"A client with antiphospholipid syndrome and a history of thrombosis requires:",["Aspirin alone","Lifelong anticoagulation with warfarin (INR 2-3) as recurrence rate without anticoagulation is > 50%","Short-term anticoagulation only","No treatment if currently no clots"],1,"APS with thrombosis: lifelong warfarin (INR 2-3, some recommend 3-4 for recurrence on standard therapy). DOACs are generally avoided for APS (TRAPS trial showed increased events with rivaroxaban in triple-positive APS). In pregnancy: LMWH + low-dose aspirin."),
  rn("NCLEX-RN","Integumentary",3,"A client with hidradenitis suppurativa has recurrent painful nodules in the axillae and groin. First-line treatment includes:",["Only incision and drainage","Topical clindamycin, systemic antibiotics (tetracyclines), and adalimumab for moderate-severe disease","Topical retinoids alone","Complete excision as first-line"],1,"HS management by severity: mild = topical clindamycin, moderate = systemic antibiotics (tetracyclines, clindamycin + rifampin), severe = biologics (adalimumab FDA-approved for HS), surgical excision of affected areas. Lifestyle: weight management, smoking cessation, loose clothing, and gentle skin care."),
  rn("RN-CAT","Critical Care",4,"A client with tension pneumothorax has tracheal deviation away from the affected side and hemodynamic collapse. The nurse should prepare for:",["CT scan for confirmation","Emergency needle decompression at the 2nd intercostal space, midclavicular line, followed by chest tube insertion","Chest X-ray first","Observation and monitoring"],1,"Tension pneumothorax is a clinical diagnosis requiring immediate needle decompression (14-16 gauge needle at 2nd ICS MCL or 4-5th ICS anterior axillary line) followed by chest tube insertion. DO NOT delay for X-ray. Signs: absent breath sounds, hypotension, JVD, tracheal deviation, tachycardia."),
  rn("NCLEX-RN","Cardiovascular",3,"A client with myocarditis presents with viral prodrome followed by chest pain and elevated troponin. The nurse should anticipate:",["Immediate cardiac catheterization","Cardiac MRI for diagnosis (late gadolinium enhancement pattern) and supportive care","Thrombolytic therapy","Antibiotic therapy"],1,"Myocarditis diagnosis: cardiac MRI is the gold standard (T2 edema, late gadolinium enhancement in mid-wall/epicardial pattern, different from MI pattern). Endomyocardial biopsy for refractory cases. Treatment: supportive (HF therapy if needed), avoid exercise, and monitor for arrhythmias."),
  rn("NCLEX-RN","Respiratory",3,"A client with tracheobronchomalacia has expiratory airflow limitation from tracheal collapse. The nurse should teach:",["Deep breathing exercises only","CPAP or positive expiratory pressure devices may help by stenting the airway open during exhalation","Inhaled corticosteroids as primary treatment","No management is available"],1,"Tracheobronchomalacia: excessive dynamic airway collapse during expiration. CPAP/BIPAP or PEP devices provide positive pressure to stent the airway open. Severe cases may require tracheal stenting or tracheobronchoplasty. Pulmonary rehabilitation improves functional capacity."),
  rn("NCLEX-RN","Neurological",3,"A client with central pontine myelinolysis (osmotic demyelination syndrome) developed this after:",["Rapid correction of hypernatremia","Rapid correction of hyponatremia (sodium should not be corrected faster than 8-10 mEq/L per 24 hours)","Normal saline administration","Adequate hydration"],1,"ODS results from overly rapid hyponatremia correction. Maximum correction rate: 8-10 mEq/L per 24 hours. Symptoms develop days after correction: dysarthria, dysphagia, quadriparesis, locked-in syndrome. Prevention is paramount. If overcorrected, relower sodium with D5W or DDAVP."),
  rn("NCLEX-RN","Endocrine",3,"A client with subclinical hypothyroidism (mildly elevated TSH with normal free T4) should be treated with levothyroxine when:",["Always, regardless of TSH level","TSH is persistently > 10 mIU/L, symptoms are present, or the patient is pregnant or planning pregnancy","Never treated until overt hypothyroidism develops","Only if symptoms of hyperthyroidism develop"],1,"Subclinical hypothyroidism treatment indications: TSH > 10 (progression to overt hypothyroidism is likely), symptomatic patients, pregnancy/planned pregnancy (affects fetal neurodevelopment), positive anti-TPO antibodies (higher progression risk). TSH 5-10: individualized decision."),
  rn("NCLEX-RN","Gastrointestinal",3,"A client with microscopic colitis has chronic watery diarrhea with normal-appearing mucosa on colonoscopy. Treatment includes:",["Bowel resection","Oral budesonide as first-line pharmacotherapy","Antibiotics","No effective treatment exists"],1,"Microscopic colitis (collagenous or lymphocytic): chronic watery diarrhea, normal colonoscopic appearance but abnormal histology. First-line: oral budesonide (80-90% response rate). Maintenance budesonide for relapsing disease. Bismuth subsalicylate and cholestyramine are alternatives for mild cases."),
  rn("NCLEX-RN","Pharmacology",3,"When switching a client from one SSRI to another, the nurse should be aware of:",["No precautions needed","Cross-tapering or appropriate washout periods to prevent serotonin syndrome or withdrawal symptoms","Immediate discontinuation and same-day switch","Double-dosing during the transition"],1,"SSRI switching strategies: cross-taper (gradually reduce one while introducing the other) for most SSRIs. Fluoxetine requires longer washout (long half-life, 5 weeks before starting MAOI). Monitor for both discontinuation syndrome (dizziness, nausea, brain zaps) and serotonin syndrome."),
  rn("NCLEX-RN","Mental Health",3,"A client with seasonal affective disorder should be treated with which evidence-based intervention?",["Only vacation to warmer climates","Light therapy (10,000 lux bright light for 20-30 minutes each morning) plus or minus SSRI therapy","Tanning beds","Increased caffeine intake"],1,"Light therapy: 10,000 lux broad-spectrum light box for 20-30 minutes each morning (simulates dawn). Start in early fall before symptoms begin. Response within 2-4 weeks. SSRIs (bupropion XL is FDA-approved for SAD prevention) may be added. CBT-SAD (behavioral activation) is also effective."),
  rn("NCLEX-RN","Pediatrics",3,"A child with congenital adrenal hyperplasia (21-hydroxylase deficiency) has ambiguous genitalia in females and salt-wasting crisis. Treatment includes:",["No treatment until puberty","Glucocorticoid and mineralocorticoid replacement therapy initiated immediately","Growth hormone therapy","Surgical correction only"],1,"CAH (21-hydroxylase deficiency): cortisol and aldosterone deficiency with androgen excess. Treatment: glucocorticoid replacement (hydrocortisone), mineralocorticoid (fludrocortisone) for salt-wasting, sodium supplementation in infancy, stress dosing during illness, and surgical consideration for virilized genitalia."),
  rn("NCLEX-RN","Maternal/Newborn",3,"A client at 41 weeks gestation should have fetal surveillance including:",["No monitoring needed","Non-stress test and amniotic fluid assessment (AFI or maximum vertical pocket) twice weekly","Monthly ultrasound only","Daily blood work"],1,"Post-term pregnancy (> 41 weeks) monitoring: twice-weekly NST and AFI assessment. Oligohydramnios (AFI < 5 or MVP < 2 cm) indicates diminished fetal reserve. Induction is recommended at 41-42 weeks. ARRIVE trial supports offering induction at 39 weeks for nulliparous women to reduce cesarean risk."),
  rn("NCLEX-RN","Renal",3,"A client with IgA vasculitis (Henoch-Schonlein purpura) nephritis should be monitored with:",["No follow-up needed","Serial urinalysis and blood pressure monitoring for at least 6 months to detect renal involvement","One-time urine check","Annual physical exam only"],1,"IgA vasculitis nephritis (IgA nephropathy on biopsy) may develop during or up to 6 months after initial presentation. Monitor urinalysis (hematuria, proteinuria) and blood pressure at least monthly for 6 months. 1-5% develop progressive CKD. Severe nephritis may require corticosteroids or immunosuppression."),
  rn("NCLEX-RN","Hematological",3,"A client with essential thrombocythemia who is pregnant requires special management because:",["No special considerations needed","High-risk for placental microvascular thrombosis; low-dose aspirin and possible cytoreduction with interferon-alpha","Hydroxyurea is safe in pregnancy","Normal platelet counts normalize during pregnancy"],1,"ET in pregnancy: increased risk of first-trimester loss (placental microvascular thrombosis), preeclampsia, and IUGR. Management: low-dose aspirin throughout, cytoreduction with interferon-alpha if needed (hydroxyurea is teratogenic), and close obstetric monitoring."),
  rn("NCLEX-RN","Cardiovascular",3,"A client with cardiac amyloidosis has infiltrative cardiomyopathy presenting as HFpEF. The nurse should know:",["Standard HF treatment is effective","Certain standard HF medications (digoxin, CCBs) may be harmful in amyloid cardiomyopathy","No treatment is available","Aggressive volume resuscitation is helpful"],1,"Cardiac amyloidosis: digoxin is contraindicated (binds to amyloid fibrils causing toxicity at low levels), CCBs may worsen heart failure, and beta-blockers should be used cautiously. Treatment depends on amyloid type: AL (chemotherapy), ATTR (tafamidis - stabilizes transthyretin). Diuretics for congestion."),
  rn("NCLEX-RN","Respiratory",3,"A client with bronchiolitis obliterans after lung transplant has progressive obstructive lung disease. This indicates:",["Normal post-transplant finding","Chronic lung allograft dysfunction (CLAD), the most common form of chronic rejection","Acute rejection that is easily reversible","Infection only"],1,"Bronchiolitis obliterans syndrome (BOS): progressive irreversible airflow obstruction representing chronic rejection. Affects 50% of lung transplant recipients by 5 years. Defined by FEV1 decline > 20% from best post-transplant baseline. Treatment: augmented immunosuppression, macrolides (azithromycin), but often refractory."),
  rn("NCLEX-RN","Neurological",3,"A client with cavernous sinus thrombosis from facial infection presents with proptosis, ophthalmoplegia, and chemosis. The nurse should anticipate:",["Outpatient antibiotics","IV antibiotics, anticoagulation, and possible surgical drainage","Warm compresses only","No treatment needed"],1,"Cavernous sinus thrombosis: life-threatening complication of facial infections (danger triangle of the face). Treatment: high-dose IV antibiotics (covering staph, strep, and anaerobes), anticoagulation (controversial but generally recommended), and surgical drainage of primary infection source. High mortality (20-30%)."),
  rn("NCLEX-RN","Endocrine",3,"A client with diabetic autonomic neuropathy may develop:",["Only peripheral numbness","Gastroparesis, orthostatic hypotension, resting tachycardia, and hypoglycemia unawareness","Improved blood pressure regulation","Enhanced exercise tolerance"],1,"Diabetic autonomic neuropathy: GI (gastroparesis, constipation/diarrhea), cardiovascular (orthostatic hypotension, resting tachycardia, silent MI), genitourinary (neurogenic bladder, erectile dysfunction), sudomotor (anhidrosis/gustatory sweating), and metabolic (hypoglycemia unawareness - loss of counter-regulatory response)."),
  rn("NCLEX-RN","Gastrointestinal",3,"A client with hemochromatosis-related liver cirrhosis should be screened for hepatocellular carcinoma with:",["Annual CT scan only","Liver ultrasound and alpha-fetoprotein (AFP) every 6 months","No screening needed","MRI annually"],1,"HCC surveillance in cirrhosis (regardless of cause): ultrasound with or without AFP every 6 months. High-risk populations include hepatitis B carriers (even without cirrhosis), and all cirrhotics from any cause. Early detection enables curative treatments (resection, transplant, ablation)."),
  rn("NCLEX-RN","Pharmacology",3,"A client prescribed oral bisphosphonates for osteoporosis should be taught to take the medication:",["At bedtime with a full meal","First thing in the morning on an empty stomach with a full glass of water, remaining upright for 30-60 minutes","With dairy products for calcium absorption","Chewed rather than swallowed"],1,"Bisphosphonate absorption is extremely poor (< 5%) and reduced further by food, calcium, and coffee. Take fasting with 8 oz plain water. Remain upright for 30-60 minutes to prevent esophageal irritation/ulceration. Do not lie down or eat other food/supplements during this period."),
  rn("NCLEX-RN","Mental Health",3,"A client with schizophrenia is prescribed a long-acting injectable antipsychotic (paliperidone palmitate). The advantage of this formulation is:",["Faster onset of action than oral medications","Improved medication adherence by eliminating daily oral dosing","Fewer side effects than oral formulations","Lower cost"],1,"Long-acting injectable antipsychotics (paliperidone palmitate monthly/3-monthly, aripiprazole lauroxil, haloperidol decanoate) improve adherence (major challenge in schizophrenia), reduce relapse and hospitalization, and provide consistent drug levels. Disadvantages: injection site reactions, inability to rapidly discontinue."),
  rn("NCLEX-RN","Pediatrics",3,"A child with Kawasaki disease who develops coronary artery aneurysms should be placed on long-term:",["No follow-up needed","Antiplatelet therapy (aspirin) and possibly anticoagulation with close cardiac follow-up","NSAIDs only","Antibiotics"],1,"KD coronary aneurysm management: small aneurysms may resolve; low-dose aspirin until resolution confirmed. Medium aneurysms: aspirin +/- clopidogrel. Giant aneurysms (> 8mm): aspirin + warfarin or LMWH. Serial echocardiography, stress testing, and possible coronary angiography for long-term monitoring."),
  rn("NCLEX-RN","Maternal/Newborn",3,"A newborn at 42 weeks gestation is classified as post-term and at increased risk for:",["Macrosomia only","Meconium aspiration syndrome, perinatal asphyxia, and placental insufficiency","Prematurity complications","No additional risks"],1,"Post-term risks: placental insufficiency (aging placenta), meconium-stained amniotic fluid (MAS risk), perinatal asphyxia, macrosomia (shoulder dystocia), oligohydramnios (cord compression), and hypoglycemia. Careful monitoring and timely induction at 41-42 weeks reduce these risks."),
  rn("NCLEX-RN","Renal",3,"A client who is an organ donor candidate must have which criterion met to be declared brain dead?",["Only absence of brain stem reflexes","Irreversible cessation of all brain function including brainstem (absence of reflexes, no respiratory drive on apnea test, and confirmatory testing)","Flat line on EEG alone","Absence of heartbeat"],1,"Brain death criteria: irreversible cause established, core temperature > 36C, no confounders (drugs, metabolic). Clinical exam: no brainstem reflexes (pupillary, corneal, gag, cough, oculocephalic, oculovestibular), no motor response, and failed apnea test. Confirmatory tests: EEG, cerebral blood flow study."),
  rn("NCLEX-RN","Cardiovascular",3,"A client with postural orthostatic tachycardia syndrome (POTS) has heart rate increase of 35 bpm upon standing. Management includes:",["Beta-blockers as sole treatment","Volume expansion (salt and fluid intake), compression garments, and graduated exercise program","Bedrest","Vasodilator therapy"],1,"POTS management: non-pharmacological first (increase salt 6-10g/day, fluid 2-3L/day, compression garments, counter-pressure maneuvers, and graduated recumbent exercise program). Pharmacological: fludrocortisone, midodrine, low-dose beta-blockers, or ivabradine. Deconditioning worsens POTS."),
  rn("NCLEX-RN","Respiratory",3,"A client with organizing pneumonia (formerly BOOP) presents with persistent consolidation despite antibiotics. The nurse should anticipate:",["More antibiotics","Corticosteroid therapy (organizing pneumonia responds dramatically to steroids)","Surgical resection","No further treatment"],1,"Organizing pneumonia: inflammatory lung disease with granulation tissue filling alveoli and bronchioles. Does NOT respond to antibiotics but responds dramatically to corticosteroids (1mg/kg prednisone for 2-4 weeks then slow taper over 6-12 months). Relapse is common with rapid tapering."),
  rn("NCLEX-RN","Neurological",3,"A client with idiopathic intracranial hypertension who fails medical therapy should be evaluated for:",["No additional treatment options","Optic nerve sheath fenestration or CSF shunting procedure to protect vision","Brain biopsy","Craniotomy"],1,"IIH refractory to weight loss and acetazolamide: optic nerve sheath fenestration (protects optic nerve from pressure damage), VP shunt or LP shunt (reduces CSF pressure), or venous sinus stenting (if venous sinus stenosis is present). Visual preservation is the primary goal."),
  rn("NCLEX-RN","Pharmacology",3,"A client receiving biologics (monoclonal antibodies ending in -mab) should understand that these medications:",["Are traditional small-molecule drugs","Are protein-based drugs that must be administered parenterally (SC or IV) and require cold-chain storage","Can be taken orally","Have no special storage requirements"],1,"Biologics are large protein molecules requiring parenteral administration (oral would destroy them). Most require refrigeration (2-8C). Side effects include injection site reactions, infusion reactions, immunogenicity (developing anti-drug antibodies reducing efficacy), and immunosuppression-related infections."),
  rn("NCLEX-RN","Mental Health",3,"A client with acute cocaine intoxication presents with chest pain, hypertension, and tachycardia. The nurse should NOT administer:",["Benzodiazepines","Non-selective beta-blockers (risk of unopposed alpha-adrenergic stimulation worsening hypertension)","Nitroglycerin","Aspirin"],1,"Cocaine blocks catecholamine reuptake causing both alpha and beta stimulation. Non-selective beta-blockers (propranolol) block beta-2 vasodilation leaving unopposed alpha vasoconstriction, potentially worsening hypertension and coronary vasospasm. Treatment: benzodiazepines, nitroglycerin, phentolamine if needed."),
  rn("NCLEX-RN","Pediatrics",3,"A child with suspected child abuse should have the nurse:",["Confront the parents immediately about the abuse","Document findings objectively, report to appropriate authorities as mandated, and ensure the child's safety","Investigate and determine guilt before reporting","Report only if the nurse is certain abuse occurred"],1,"Nurses are mandated reporters: required to report suspected (not proven) abuse. Document objectively (exact quotes, detailed description of injuries, behavior), take photographs per protocol, report to child protective services/law enforcement, and ensure the child's immediate safety. Do not investigate independently."),
  rn("NCLEX-RN","Maternal/Newborn",3,"A client with hyperemesis gravidarum has persistent vomiting, ketonuria, and weight loss > 5%. Treatment includes:",["Encouraging oral intake without IV support","IV hydration, electrolyte replacement, thiamine supplementation, and antiemetic therapy","No treatment as it always resolves","Immediate termination of pregnancy"],1,"Hyperemesis gravidarum: severe nausea/vomiting causing dehydration, ketonuria, weight loss > 5%, and electrolyte abnormalities. Treatment: IV fluid resuscitation, electrolyte correction, thiamine (prevent Wernicke), antiemetics (ondansetron, metoclopramide, promethazine), and gradual dietary advancement."),
  rn("NCLEX-RN","Renal",3,"A client with Alport syndrome has hematuria, hearing loss, and ocular abnormalities. The nurse should understand this is:",["An acquired condition from UTIs","A hereditary collagen IV disorder affecting the kidneys, ears, and eyes","A temporary condition","Related to diabetes"],1,"Alport syndrome: X-linked dominant (most common form) mutation in type IV collagen affecting glomerular basement membrane, cochlea, and lens. Males: progressive ESRD by age 20-30, sensorineural hearing loss, anterior lenticonus. Females: usually carriers with milder disease. Treatment: ACEi slows progression."),
  rn("NCLEX-RN","Hematological",3,"A client with cold agglutinin disease develops hemolytic anemia worsened by cold temperatures. Management includes:",["Blood transfusion through a standard blood warmer","Avoidance of cold exposure and warming all IV fluids; rituximab for symptomatic disease","Cold compress application","Iron supplementation alone"],1,"Cold agglutinin disease: IgM autoantibodies cause complement-mediated hemolysis at temperatures < 37C. Management: avoid cold, warm IV fluids and blood products, rituximab for symptomatic disease, and sometimes complement inhibitors (sutimlimab - FDA approved). DAT positive for complement (C3d), negative for IgG."),
  rn("NCLEX-RN","Immunological",3,"A client with mixed connective tissue disease has overlapping features of SLE, scleroderma, and polymyositis. The characteristic antibody is:",["Anti-dsDNA","Anti-U1 RNP (anti-ribonucleoprotein)","Anti-Scl-70","Anti-Jo-1"],1,"MCTD: high titer anti-U1 RNP antibodies with overlapping features of SLE (rash, arthritis), scleroderma (Raynaud, skin thickening), and polymyositis (proximal muscle weakness). Treatment targets the predominant features. Pulmonary hypertension is the major cause of mortality."),
  rn("NCLEX-RN","Integumentary",3,"A client with pyoderma gangrenosum should NOT have the wound surgically debrided because:",["The wound is too small","Surgical debridement causes pathergy (worsening of the wound at sites of trauma)","The wound will heal with antibiotics alone","Anesthesia is contraindicated"],1,"Pyoderma gangrenosum: neutrophilic dermatosis causing painful, rapidly progressive skin ulceration. Pathergy (worsening with trauma/surgery) is a hallmark. Treatment: topical/systemic corticosteroids, cyclosporine, infliximab. Associated with IBD, rheumatoid arthritis, and hematological malignancies."),
  rn("RN-CAT","Critical Care",4,"A client with acute liver failure develops cerebral edema. The nurse should:",["Elevate HOB to 90 degrees","Elevate HOB 30 degrees, administer hypertonic saline or mannitol, and avoid stimulation","Perform frequent neurological assessments using painful stimuli","Administer lactulose aggressively"],1,"ALF with cerebral edema management: HOB 30 degrees, hypertonic saline (target Na 145-155), mannitol for acute herniation, avoid stimulation, quiet dark environment, hypothermia (32-34C controversial but may be used), and ICP monitoring when possible. Lactulose role is limited in ALF."),
  rn("NCLEX-RN","Cardiovascular",3,"A client with peripartum cardiomyopathy develops heart failure in the last month of pregnancy or within 5 months postpartum. The nurse should know:",["This always resolves completely","Recovery occurs in about 50% of patients; bromocriptine may aid recovery","The condition is always permanent","Pregnancy has no cardiac effects"],1,"PPCM: dilated cardiomyopathy (EF < 45%) in late pregnancy or early postpartum without other cause. Recovery in 50-70% within 6 months. Treatment: standard HF medications (ACEi/ARB after delivery only), beta-blockers, bromocriptine (may improve recovery), and wearable defibrillator for EF < 35%."),
  rn("NCLEX-RN","Respiratory",3,"A client who had a near-drowning episode should be monitored for at least 24 hours because:",["No monitoring is needed if the client appears stable","Delayed pulmonary edema can develop hours after the submersion event","Only hypothermia is a concern","Cardiac complications do not occur"],1,"Near-drowning complications can be delayed: non-cardiogenic pulmonary edema (ARDS from surfactant washout and direct alveolar injury), hypothermia, aspiration pneumonia, and electrolyte abnormalities. Monitor SpO2, respiratory status, and CXR for at least 24 hours. Intubation may be needed for worsening oxygenation."),
  rn("NCLEX-RN","Neurological",3,"A client with a chronic pain syndrome should be managed with a multimodal approach including:",["Opioid monotherapy long-term","Non-pharmacological approaches (CBT, physical therapy), non-opioid medications, and interventional procedures","Complete bed rest","Avoiding all physical activity"],1,"Chronic pain multimodal approach: physical therapy, cognitive behavioral therapy, non-opioid medications (gabapentin, duloxetine, NSAIDs, TCAs), interventional procedures (nerve blocks, spinal cord stimulation), complementary therapies (acupuncture, mindfulness), and exercise. Opioids are last-line and require careful monitoring."),
  rn("NCLEX-RN","Gastrointestinal",3,"A client with primary sclerosing cholangitis should be monitored for which malignancy?",["Hepatocellular carcinoma only","Cholangiocarcinoma (occurs in 5-10% of PSC patients over their lifetime)","Colon cancer only","No malignancy risk",""],1,"PSC: progressive bile duct inflammation and fibrosis, strongly associated with IBD (especially UC). Cholangiocarcinoma risk 5-10% (highest among chronic liver diseases). Surveillance with annual MRI/MRCP and CA 19-9. Also increased colorectal cancer risk (annual colonoscopy with UC/PSC)."),
  rn("NCLEX-RN","Pharmacology",3,"A client on phenytoin therapy with a declining albumin level should have the dose adjusted because:",["Albumin has no effect on drug levels","Phenytoin is highly protein-bound; low albumin increases free (active) drug levels, risking toxicity even with normal total levels","Low albumin means the drug is less effective","Albumin supplements replace the need for dose adjustment"],1,"Phenytoin is 90% protein-bound. Hypoalbuminemia increases free (unbound) phenytoin causing toxicity despite 'normal' total levels. Use corrected phenytoin formula: corrected = measured / (0.2 x albumin + 0.1). Or measure free phenytoin level directly. Adjust dose accordingly."),
  rn("NCLEX-RN","Mental Health",3,"A client with autism spectrum disorder in adulthood should have the nurse focus on:",["Curing the condition","Supporting independence, social skills, vocational training, and managing co-occurring conditions","Isolating the client from social settings","Intensive behavioral therapy identical to childhood protocols"],1,"Adult ASD management: supported independence (structured routines, clear communication), social skills groups, vocational training and supported employment, managing co-occurring conditions (anxiety, depression, ADHD - common), and psychoeducation. Individualized approach respecting neurodiversity while addressing functional challenges."),
  rn("NCLEX-RN","Pediatrics",3,"A child with juvenile idiopathic arthritis should be treated early to prevent:",["Only pain","Joint damage and growth disturbance from chronic synovial inflammation","Skin rashes","Respiratory problems"],1,"JIA early aggressive treatment prevents irreversible joint damage and growth disturbances: NSAIDs, intra-articular corticosteroids, DMARDs (methotrexate first-line), and biologics (etanercept, adalimumab, tocilizumab) for refractory disease. Physical therapy maintains joint function. Regular ophthalmologic exams (uveitis screening)."),
  rn("NCLEX-RN","Maternal/Newborn",3,"A client with vasa previa identified on prenatal ultrasound should be managed with:",["Vaginal delivery at term","Planned cesarean delivery at 34-37 weeks before labor onset or membrane rupture","Induction of labor at 39 weeks","No special management"],1,"Vasa previa: fetal vessels cross the internal os unprotected by placenta or cord. Membrane rupture or cervical dilation can rupture these vessels causing rapid fetal exsanguination (fetal mortality > 50% if undiagnosed). Planned cesarean at 34-37 weeks with antenatal corticosteroids. Hospitalization may be recommended."),
  rn("NCLEX-RN","Renal",3,"A client with cast nephropathy (myeloma kidney) should receive:",["Normal saline restriction","Aggressive IV hydration to maintain high urine output and alkalinize urine, plus treatment of the underlying myeloma","Diuretics to reduce kidney swelling","No specific renal treatment"],1,"Cast nephropathy in multiple myeloma: monoclonal light chains form obstructing casts in renal tubules. Treatment: aggressive hydration (3L/day), avoid nephrotoxins (NSAIDs, contrast, aminoglycosides), alkalinize urine (sodium bicarbonate), treat the myeloma (chemotherapy), and plasmapheresis in select cases."),

  // === NP (25 - targets 99 more needed) ===
  np("AANP","Cardiovascular",3,"A patient with chest pain and negative troponin and ECG should be risk-stratified using:",["Clinical judgment alone","HEART score (History, ECG, Age, Risk factors, Troponin) to guide disposition","Immediate cardiac catheterization","No further evaluation needed"],1,"HEART score: 0-3 (low risk, consider discharge with follow-up), 4-6 (moderate, observation/further testing), 7-10 (high, early invasive strategy). Validated tool for ED chest pain evaluation. Low HEART score with negative troponins has < 2% 30-day MACE rate."),
  np("AANP","Respiratory",3,"A patient with bronchiectasis should be managed with:",["Short-course antibiotics only when symptomatic","Airway clearance therapy, prompt treatment of exacerbations, and possible long-term macrolide for frequent exacerbations","Inhaled corticosteroids as sole therapy","No long-term management needed"],1,"Bronchiectasis management: daily airway clearance (high-frequency chest wall oscillation, flutter valve, postural drainage), prompt antibiotic treatment of exacerbations (culture-directed), low-dose macrolide for >= 3 exacerbations/year, and influenza/pneumococcal vaccination. CT chest defines disease extent."),
  np("NP-CAT","Neurological",3,"A patient with suspected temporal arteritis (giant cell arteritis) should have:",["Wait for biopsy results before treatment","Immediate high-dose corticosteroids started BEFORE temporal artery biopsy (do not delay treatment for biopsy)","NSAIDs as sole treatment","No treatment if ESR is normal"],1,"GCA with visual symptoms (amaurosis fugax, diplopia) is an ophthalmologic emergency. Start IV methylprednisolone immediately, then high-dose oral prednisone (40-60mg). Biopsy within 14 days (steroids do not affect pathology for up to 2 weeks). ESR/CRP elevated but can be normal in 5%. Tocilizumab is steroid-sparing."),
  np("AANP","Endocrine",3,"A patient with a newly diagnosed thyroid nodule and normal TSH should have:",["Immediate thyroidectomy","Ultrasound evaluation to assess nodule characteristics and determine if FNA is needed","Only observation without imaging","Radioactive iodine scan as first step"],1,"Thyroid nodule workup: check TSH first. If normal/elevated TSH: ultrasound to characterize nodule (size, echogenicity, margins, calcifications, vascularity). US features determine FNA threshold per ACR TI-RADS or ATA risk stratification. If suppressed TSH: thyroid scan (hot nodules rarely malignant)."),
  np("AANP","Gastrointestinal",3,"A patient with chronic constipation refractory to dietary changes and osmotic laxatives should be evaluated for:",["No further workup","Defecatory disorders (anorectal manometry and balloon expulsion test) and colonic transit study","Colonoscopy only","Psychiatric evaluation"],1,"Refractory constipation workup: anorectal manometry (assesses sphincter function and coordination), balloon expulsion test (screen for defecatory disorders), and colonic transit study (slow transit constipation vs. outlet obstruction). Defecatory disorders respond to biofeedback therapy. Slow transit may need prokinetics."),
  np("NP-CAT","Pharmacology",3,"A patient on multiple CYP3A4 substrate medications should have the NP aware that which common foods/drugs inhibit this enzyme?",["Bananas","Grapefruit juice and certain azole antifungals (CYP3A4 inhibitors increase drug levels)","Whole grains","Lean meats"],1,"CYP3A4 metabolizes 50%+ of medications. Inhibitors (increase drug levels): grapefruit, ketoconazole, itraconazole, erythromycin, clarithromycin, diltiazem, verapamil, ritonavir. Inducers (decrease levels): rifampin, carbamazepine, phenytoin, St. John's wort. Clinical significance varies by drug."),
  np("AANP","Mental Health",3,"A patient with PTSD should understand that evidence-based treatment includes:",["Benzodiazepines as first-line","Trauma-focused CBT (prolonged exposure or cognitive processing therapy) and SSRI/SNRI pharmacotherapy","Antipsychotics as first-line","Only crisis intervention"],1,"PTSD evidence-based treatment: PE (graduated exposure to trauma memories and avoided situations), CPT (examining unhelpful trauma-related thoughts), EMDR (desensitization through bilateral stimulation). Pharmacotherapy: sertraline and paroxetine (FDA-approved for PTSD), venlafaxine. Prazosin for trauma-related nightmares."),
  np("AANP","Dermatology",3,"A patient with tinea capitis should be treated with:",["Topical antifungal cream alone","Oral antifungal therapy (griseofulvin or terbinafine) as topical agents cannot penetrate hair follicles","Topical corticosteroids","Antibiotics"],1,"Tinea capitis requires systemic antifungal therapy because topical agents cannot reach fungi within the hair shaft and follicle. Griseofulvin (6-12 weeks, taken with fatty food) or terbinafine (4-6 weeks). Selenium sulfide or ketoconazole shampoo adjunctively reduces fungal shedding."),
  np("AANP","Musculoskeletal",3,"A patient with a positive Lachman test and anterior drawer test likely has:",["Meniscal tear","Anterior cruciate ligament (ACL) tear","Posterior cruciate ligament tear","Medial collateral ligament sprain"],1,"Lachman test: most sensitive for ACL tear (anterior tibial translation with the knee at 20-30 degrees flexion). Anterior drawer test: less sensitive (knee at 90 degrees). MRI confirms the diagnosis. ACL reconstruction is recommended for active individuals. Conservative management with PT for less active patients."),
  np("NP-CAT","Infectious Disease",3,"A patient with HIV should be started on antiretroviral therapy:",["Only when CD4 count drops below 200","Immediately upon diagnosis regardless of CD4 count (treat all approach)","Only when symptoms develop","After 6 months of monitoring"],1,"START trial: immediate ART for all HIV-positive individuals regardless of CD4 count reduces AIDS-defining events and serious non-AIDS conditions. Rapid ART initiation (same day or within 7 days of diagnosis) improves outcomes and retention in care. ART also prevents transmission (U=U: undetectable = untransmittable)."),
  np("AANP","Reproductive",3,"A patient with primary dysmenorrhea should be offered first-line treatment with:",["Opioid analgesics","NSAIDs started at onset of menses (or 1-2 days before) and/or hormonal contraceptives","Muscle relaxants","Acetaminophen only"],1,"Primary dysmenorrhea first-line: NSAIDs (prostaglandin synthesis inhibitors - directly address the pathophysiology). Start 1-2 days before menses and continue through heaviest days. Hormonal contraceptives (combined OCP, LNG-IUD) reduce menstrual flow and prostaglandin production. Non-pharmacological: heat, exercise."),
  np("AANP","Geriatrics",3,"The NP should perform medication reconciliation for an elderly patient to identify potential:",["Only drug allergies","Drug-drug interactions, therapeutic duplication, and medications with no current indication","The cheapest medications","The newest medications available"],1,"Medication reconciliation goals: identify duplications, drug-drug/drug-disease interactions, medications lacking indication, incorrect doses (especially for renal/hepatic function), potentially inappropriate medications (Beers Criteria), and adherence barriers. Deprescribing should be considered at each visit."),
  np("NP-CAT","Hematological",3,"A patient with newly diagnosed deep vein thrombosis should receive:",["Warfarin alone from the start","Direct oral anticoagulant (apixaban or rivaroxaban preferred) or LMWH bridging to warfarin for at least 3 months","Aspirin only","Thrombolytic therapy for all DVTs"],1,"DVT treatment: DOACs preferred (apixaban, rivaroxaban - no bridging needed; edoxaban, dabigatran require 5 days LMWH lead-in). Alternative: LMWH bridging to warfarin (INR 2-3). Duration: provoked DVT 3 months, unprovoked >= 3 months (consider indefinite based on risk/benefit assessment)."),
  np("AANP","Renal",3,"A patient with hyperuricemia and gout should have urate-lowering therapy dose adjusted to achieve a target serum uric acid of:",["Below 10 mg/dL","Below 6 mg/dL (promotes dissolution of urate crystals and prevents new crystal formation)","Below 8 mg/dL","No specific target"],1,"Target serum uric acid < 6 mg/dL (some recommend < 5 for tophaceous gout). This level promotes dissolution of monosodium urate crystals and prevents new crystal formation. Allopurinol: start 100mg, increase by 100mg every 2-4 weeks to target. Check HLA-B*5801 in at-risk populations before starting."),
  np("AANP","Women's Health",3,"A patient with stress urinary incontinence should be offered first-line treatment with:",["Immediate surgery","Pelvic floor muscle exercises (Kegels) and behavioral modifications","Anticholinergic medications","Catheterization"],1,"Stress UI first-line: pelvic floor muscle training (Kegel exercises - at least 3 months of regular practice), bladder training, weight loss if overweight, and pessary fitting. Surgery (mid-urethral sling) for persistent symptoms after conservative measures. Anticholinergics are for OVERACTIVE bladder, not stress UI."),
  np("AANP","Preventive Medicine",2,"The NP should recommend which cancer screening for average-risk women aged 40-49?",["No screening needed until age 50","Shared decision-making about mammography screening, with biennial screening recommended starting at age 50 (USPSTF 2024 updated to recommend starting at 40)","Annual mammography is universally required","Only clinical breast exam"],1,"USPSTF 2024 update: recommend biennial mammography starting at age 40 for average-risk women (changed from age 50). ACS recommends annual mammography starting at 45 (biennial at 55). ACR recommends annual starting at 40. Shared decision-making about screening frequency and starting age."),
  np("AANP","Cardiovascular",3,"A patient with peripheral arterial disease should be offered which medication for symptom improvement?",["Beta-blockers for claudication","Cilostazol (PDE3 inhibitor) for intermittent claudication","Warfarin","Calcium channel blockers"],1,"Cilostazol: PDE3 inhibitor with vasodilatory and antiplatelet properties, improves walking distance in intermittent claudication by 40-60%. Contraindicated in heart failure. Supervised exercise programs (walking 30-45 min, 3x/week) provide similar or greater benefit. Pentoxifylline is an alternative but less effective."),
  np("NP-CAT","Respiratory",4,"A patient with interstitial lung disease of unknown cause should have the diagnosis confirmed with:",["CT scan alone is always sufficient","High-resolution CT (HRCT) and if the pattern is atypical, multidisciplinary discussion and possible surgical lung biopsy","Chest X-ray only","PFTs alone"],1,"ILD diagnosis: HRCT is the cornerstone (UIP pattern is diagnostic of IPF in appropriate clinical context). If HRCT is indeterminate, multidisciplinary discussion (pulmonologist, radiologist, pathologist) determines if surgical lung biopsy (VATS) is needed. Serological testing for autoimmune ILD."),
  np("AANP","Endocrine",3,"A patient with diabetic foot ulcer should be managed with:",["Only wound dressings","Offloading (total contact cast or removable cast walker), wound debridement, infection management, and vascular assessment","Antibiotics for all ulcers regardless of infection","Amputation as first treatment"],1,"Diabetic foot ulcer management: offloading pressure (TCC gold standard), debridement of necrotic tissue, moisture management, infection assessment and treatment when present (mild: oral antibiotics, moderate-severe: IV), vascular evaluation (ABI, duplex), and glycemic optimization. Multidisciplinary foot care team."),
  np("AANP","Gastrointestinal",3,"A patient with a positive fecal immunochemical test (FIT) should have:",["Repeat FIT in 1 year","Diagnostic colonoscopy to evaluate for colorectal pathology","No follow-up if asymptomatic","CT colonography as an alternative"],1,"Positive FIT requires diagnostic colonoscopy regardless of symptoms. FIT detects hemoglobin from lower GI bleeding (higher specificity for CRC than guaiac FOBT). A positive FIT has 3-5% probability of CRC and 20-30% probability of advanced adenoma. Colonoscopy should be completed within 6 months of positive FIT."),
  np("NP-CAT","Mental Health",3,"A patient presenting with new-onset psychosis should have the NP rule out:",["Only psychiatric causes","Medical causes including thyroid disorders, vitamin deficiencies (B12), autoimmune encephalitis, brain tumors, and substance use","Malingering only","Depression"],1,"New-onset psychosis workup: CBC, CMP, TSH, B12/folate, RPR, HIV, urinalysis, urine drug screen, brain MRI (structural lesions), and possibly EEG and lumbar puncture (autoimmune encephalitis, particularly anti-NMDA receptor). Medical causes must be excluded before diagnosing a primary psychiatric disorder."),

  // === RPN (50 - targets 147 more needed) ===
  rpn("REX-PN","Cardiovascular",2,"A client with newly diagnosed heart failure should be taught to weigh themselves:",["Once a month","Daily at the same time in similar clothing, reporting a gain of 2 lbs or more in one day or 5 lbs in one week","Only when they feel swollen","Weekly at any time of day"],1,"Daily weights are the most sensitive indicator of fluid retention in HF. Weigh same time each morning after voiding, wearing similar clothing, using the same scale. Report weight gain > 2 lbs in 1 day or > 5 lbs in 1 week (indicates fluid retention requiring treatment adjustment)."),
  rpn("REX-PN","Cardiovascular",2,"A client receiving an anticoagulant injection (enoxaparin) should have the injection administered in the:",["Deltoid muscle by IM injection","Subcutaneous tissue of the abdomen, alternating sides","Gluteal muscle by deep IM injection","Intravenous route"],1,"Enoxaparin (LMWH) is administered subcutaneously in the anterolateral or posterolateral abdominal wall. Do not aspirate or rub the injection site (prevents bruising). Alternate sides with each injection. Maintain 2-inch distance from the navel. Do not expel the air bubble."),
  rpn("REX-PN","Respiratory",2,"A client with COPD should receive the influenza vaccine:",["Never, as they are immunocompromised","Annually as respiratory infections can cause severe COPD exacerbations","Only during a COPD exacerbation","Every 5 years"],1,"COPD patients are at high risk for influenza complications (exacerbations, pneumonia, hospitalization). Annual influenza vaccination reduces morbidity and mortality. Pneumococcal vaccination is also recommended. Live attenuated intranasal vaccine is NOT recommended for COPD patients (use inactivated injectable form)."),
  rpn("RPN-CAT","Neurological",3,"A client with a stroke has dysphagia. Before providing oral feeding, the nurse should ensure:",["The client can speak clearly","A bedside swallowing assessment or formal swallowing study has been completed","The client requests food","The family brings preferred foods"],1,"Dysphagia screening within 24 hours of stroke admission prevents aspiration pneumonia. Bedside assessment: observe alertness, voice quality (wet/gurgly), cough strength, and trial sips. If concerns, speech-language pathology referral for formal assessment (VFSS or FEES). NPO until cleared."),
  rpn("REX-PN","Endocrine",2,"A client with diabetes should check blood glucose more frequently during:",["Periods of consistent routine","Illness, stress, changes in medication, diet, or exercise routine","Good glycemic control periods","Sleep"],1,"Glucose monitoring frequency increases during illness (counter-regulatory hormones raise glucose), medication changes (dose adjustments), dietary changes, increased/decreased activity, stress, and new symptoms. Sick day rules: check every 2-4 hours, monitor ketones if glucose > 250 mg/dL."),
  rpn("REX-PN","Gastrointestinal",2,"A client post-appendectomy should be assessed for which complication?",["Chronic diarrhea","Surgical site infection, paralytic ileus, and intra-abdominal abscess","Liver failure","Chronic constipation permanently"],1,"Post-appendectomy complications: surgical site infection (fever, wound drainage), paralytic ileus (absent bowel sounds, distension, nausea), intra-abdominal abscess (persistent fever, pain), and rarely, small bowel obstruction from adhesions. Monitor: vital signs, wound assessment, bowel function, and pain."),
  rpn("REX-PN","Pharmacology",2,"A client prescribed eye drops should be taught to:",["Instill drops directly onto the cornea","Pull down the lower eyelid and instill drops into the conjunctival sac, then close eyes gently","Touch the dropper tip to the eye for precise placement","Apply heavy pressure to the eye after instillation"],1,"Eye drop technique: tilt head back, pull down lower lid to form a pocket (conjunctival sac), instill drop into pocket (not on cornea), close eyes gently for 1-2 minutes, apply gentle pressure to the nasolacrimal duct (inner corner) to reduce systemic absorption. Do not touch dropper to eye."),
  rpn("REX-PN","Mental Health",2,"The nurse should know that setting limits with clients exhibiting manipulative behavior is:",["Punitive and should be avoided","A therapeutic intervention that provides structure, safety, and consistency","Only done when the behavior is extreme","Harmful to the therapeutic relationship"],1,"Setting limits is a therapeutic tool that provides clear expectations and consequences, promotes safety, and teaches appropriate behavior. Apply consistently (all staff use the same approach), communicate matter-of-factly (not punitively), and explain the rationale. Limits should be realistic and enforceable."),
  rpn("REX-PN","Pediatrics",2,"When administering medications to a toddler, the nurse should:",["Mix medication with the entire bottle of formula","Use a calibrated syringe and administer in small amounts into the side of the cheek","Squirt medication to the back of the throat quickly","Tell the child the medicine is candy"],1,"Toddler medication administration: use calibrated syringe or dropper, position semi-upright, administer slowly into the side of the cheek (reduces gagging and aspiration risk). Do not add to an entire bottle (if not finished, dose is incomplete). Never call medicine candy (safety risk)."),
  rpn("REX-PN","Fundamentals",2,"Informed consent requires that the client understands:",["Only the name of the procedure","The procedure, its risks, benefits, alternatives, and the right to refuse","Only what the nurse thinks is important","Nothing specific, just a signature"],1,"Informed consent elements: nature of the procedure, risks and potential complications, expected benefits, alternatives (including no treatment), and the right to refuse or withdraw consent at any time. The physician obtains consent; the nurse ensures understanding and witnesses the signature."),
  rpn("REX-PN","Musculoskeletal",2,"A client with osteoarthritis should be encouraged to:",["Avoid all physical activity","Engage in low-impact exercise (swimming, walking, cycling) to maintain joint mobility and muscle strength","Perform vigorous high-impact exercise","Remain on strict bed rest"],1,"Low-impact exercise improves joint function, reduces pain, strengthens supporting muscles, and maintains range of motion. Swimming and water aerobics are ideal (buoyancy reduces joint stress). Walking and cycling are also beneficial. Avoid high-impact activities that stress damaged joints."),
  rpn("REX-PN","Renal",2,"A client with acute kidney injury should have fluid intake carefully managed. The nurse should monitor:",["Only blood pressure","Intake and output, daily weight, serum electrolytes, and BUN/creatinine","Only urine color","Only oral intake"],1,"AKI monitoring: strict I&O (urine output is a key indicator of renal function), daily weight (fluid balance), serum electrolytes (especially potassium - hyperkalemia risk), BUN/creatinine (rising indicates worsening), and vital signs. Fluid management depends on the oliguric vs. non-oliguric status."),
  rpn("REX-PN","Maternal/Newborn",2,"The nurse should teach a new mother that breastfeeding should be initiated:",["Within 24 hours of birth","As soon as possible within the first hour of life (golden hour) to promote bonding and milk production","Only after the infant cries loudly","After formula is tried first"],1,"Early initiation of breastfeeding (within the first hour): promotes skin-to-skin bonding, stimulates prolactin and oxytocin release (establishing milk production), provides colostrum (rich in antibodies), and supports newborn thermoregulation and glucose stability."),
  rpn("REX-PN","Infection Control",2,"Proper technique for removing contaminated gloves includes:",["Pulling them off quickly by the fingertips","Grasping the outside of one glove near the wrist, peeling off inside out, then sliding fingers under the remaining glove and peeling off inside out","Removing gloves by pulling from each finger","Using teeth to remove tight gloves"],1,"Contaminated glove removal: grasp outside of one glove near wrist, peel off turning inside out, hold in gloved hand. Slide ungloved fingers under remaining glove wrist, peel off over first glove (inside out containing the first glove). Dispose in appropriate waste and perform hand hygiene immediately."),
  rpn("REX-PN","Hematological",2,"A client receiving a blood transfusion should have vital signs monitored:",["Only at the beginning and end","Before starting, 15 minutes after starting, and then at intervals per facility policy","Only if the client reports symptoms","Once during the transfusion"],1,"Blood transfusion monitoring: baseline vital signs before starting, at 15 minutes (most acute reactions occur within first 15-30 minutes), then per facility protocol (typically every 30-60 minutes during transfusion, and post-completion). Stay with the patient for the first 15 minutes."),
  rpn("REX-PN","Integumentary",2,"A client with a surgical wound healing by secondary intention should expect:",["Quick closure with sutures","Wound healing from the base upward through granulation, contraction, and epithelialization","No healing is possible","Immediate skin grafting for all wounds"],1,"Secondary intention healing: wound left open to fill from the base with granulation tissue (red, moist, beefy appearance), then wound contracts (wound edges draw together), and finally epithelial cells migrate across the surface. Takes longer than primary intention. Keep wound moist and clean."),
  rpn("REX-PN","Emergency",2,"The priority action when discovering an unconscious adult is:",["Begin chest compressions immediately","Check for responsiveness and call for help, then check breathing and pulse","Move the person to a hospital bed","Administer epinephrine"],1,"BLS sequence: Check scene safety, check responsiveness (tap and shout), activate emergency response (call 911/code), check breathing and pulse simultaneously (no longer than 10 seconds). If no pulse and not breathing: begin CPR (30:2 ratio), attach AED when available."),
  rpn("REX-PN","Oncology",2,"A client receiving radiation therapy to the chest area should be taught to:",["Scrub the treatment area vigorously","Protect the treated skin from sun exposure, avoid harsh products, and report skin changes","Apply adhesive bandages to the treatment marks","Use hot compresses on the treatment area"],1,"Radiation skin care: avoid sun exposure to treatment area, use mild soap, pat dry gently, no lotions/creams unless prescribed, wear soft loose cotton clothing, do not remove treatment markings, and report skin changes (erythema, desquamation, blistering). Apply prescribed skin care products."),
  rpn("REX-PN","Safety",2,"Medication administration through a wrong route is a type of:",["Normal variation","Medication error requiring incident reporting and client assessment","An acceptable alternative if the dose is correct","Not a concern if no adverse effects occur"],1,"Wrong route = medication error requiring: immediate assessment of the client (adverse effects), notification of the provider, incident report filing, and documentation. Even if no adverse effects occur, the error must be reported. Root cause analysis identifies system improvements to prevent recurrence."),
  rpn("REX-PN","Geriatrics",2,"Atypical presentation of myocardial infarction in the elderly may include:",["Always crushing chest pain","Confusion, fatigue, dyspnea, or syncope without typical chest pain","Only elevated blood pressure","Always diaphoresis and nausea"],1,"Elderly MI: atypical presentations are common (up to 40%). May present with confusion/altered mental status, fatigue, dyspnea, syncope, falls, nausea/vomiting, or abdominal pain rather than classic chest pain. Maintain high index of suspicion and obtain ECG and troponin liberally."),
  rpn("REX-PN","Ethics/Legal",2,"A client has an advance directive requesting no CPR. During a cardiac arrest, the nurse should:",["Override the directive and begin CPR","Respect the advance directive and not initiate CPR, providing comfort measures","Begin CPR and contact the family to decide","Ignore the directive if no family is present"],1,"Advance directives are legally binding expressions of the client's wishes. DNR orders must be respected. The nurse provides comfort measures (positioning, suctioning, oxygen for comfort). Document actions and notify the provider. Ensure the advance directive is in the medical record and current."),
  rpn("REX-PN","Delegation",2,"The RPN should NOT delegate which task to unlicensed assistive personnel?",["Taking vital signs","Initial assessment and clinical judgment-based decision making","Ambulation assistance","Feeding assistance"],1,"The nurse retains tasks requiring professional nursing judgment: initial and ongoing assessment, care planning, nursing diagnosis, evaluation of outcomes, teaching, and any task requiring clinical decision-making. UAPs can perform tasks that are routine, repetitive, and do not require professional judgment."),
  rpn("REX-PN","Health Promotion",2,"Colorectal cancer screening using a fecal immunochemical test (FIT) should be performed:",["Every 5 years","Annually for average-risk adults beginning at age 45-50","Only once in a lifetime","Monthly"],1,"FIT annually is recommended for average-risk CRC screening (age 45 per USPSTF 2021 update, previously 50). FIT detects human hemoglobin in stool (specific to lower GI). Positive FIT requires follow-up colonoscopy. FIT is preferred over guaiac FOBT due to higher sensitivity and specificity."),
  rpn("REX-PN","Nutrition",2,"A client with heart failure should limit daily sodium intake to:",["No restriction necessary","Less than 2,000 mg (2 grams) per day","Less than 5,000 mg per day","Less than 500 mg per day"],1,"HF sodium restriction: < 2g/day reduces fluid retention and symptoms. Teach label reading (check serving sizes), avoid processed/canned foods, use herbs/spices instead of salt, and be aware of hidden sodium sources (sauces, condiments, medications like antacids)."),
  rpn("REX-PN","Wound Care",2,"The nurse assessing a wound should document:",["Only the wound size","Size (length, width, depth), wound bed appearance, drainage (type, amount, odor), periwound skin condition, and signs of infection","Only whether the wound is open or closed","Only the presence of a dressing"],1,"Comprehensive wound documentation: size (LxWxD in cm), wound bed (granulation, slough, necrotic tissue percentage), drainage/exudate (serous, sanguineous, purulent; amount), periwound skin (maceration, erythema, induration), tunneling/undermining, pain, and signs of infection."),
  rpn("REX-PN","Community Health",2,"Discharge planning should begin:",["On the day of discharge","At the time of admission to ensure a safe and timely transition of care","After the client requests it","Only if the family asks for it"],0,"Discharge planning begins at admission: assess anticipated needs, identify barriers, involve the client and family, coordinate with interdisciplinary team, arrange follow-up appointments, ensure medication understanding, and provide written discharge instructions. Early planning reduces readmission rates."),
  rpn("REX-PN","Cardiovascular",3,"A client with heart failure should be taught to recognize which signs of worsening condition?",["Decreased appetite only","Increasing shortness of breath, swelling in legs/feet, sudden weight gain, and persistent cough","Only nausea","Only fatigue"],1,"HF decompensation signs: increasing dyspnea (especially orthopnea, PND), peripheral edema, rapid weight gain (fluid retention), persistent cough (pulmonary congestion), fatigue, decreased exercise tolerance, and decreased appetite. Early recognition and reporting prevent hospitalization."),
  rpn("REX-PN","Respiratory",2,"A client with asthma should use their peak flow meter to:",["Monitor oxygen levels","Monitor airflow to detect early signs of an asthma attack before symptoms worsen","Replace spirometry testing","Measure respiratory rate"],1,"Peak flow monitoring: establishes personal best, identifies early airflow decline before symptoms appear. Green zone (80-100% personal best: well-controlled), Yellow zone (50-80%: caution, take quick-relief medication), Red zone (< 50%: medical emergency). Track trends and use to guide action plan."),
  rpn("REX-PN","Neurological",2,"A client who has experienced a transient ischemic attack should be educated that:",["TIA is not serious and does not require follow-up","TIA is a warning sign of impending stroke requiring urgent evaluation and preventive treatment","TIA is the same as a stroke with permanent damage","Only observation is needed without medication"],1,"TIA is a medical emergency: 10-15% stroke risk within 90 days (highest in first 48 hours). Requires urgent evaluation (brain imaging, carotid assessment, cardiac workup), antiplatelet therapy, management of risk factors (hypertension, diabetes, smoking, lipids), and possible intervention (carotid endarterectomy if significant stenosis)."),
  rpn("REX-PN","Endocrine",2,"A client with Addison disease should be taught to carry emergency identification and extra medication because:",["It is hospital policy","Adrenal crisis can occur during stress, illness, or surgery requiring increased corticosteroid doses (stress dosing)","Medications expire quickly","Other healthcare providers need to know the medication name"],1,"Adrenal crisis can be life-threatening: the body cannot produce adequate cortisol during physiological stress. Stress dosing (doubling or tripling hydrocortisone dose during illness, injury, or surgery) prevents crisis. Medical alert identification ensures appropriate emergency treatment. IM hydrocortisone injection kit for emergencies."),
  rpn("REX-PN","Gastrointestinal",2,"A client with inflammatory bowel disease should avoid:",["All dairy products permanently","NSAIDs as they can trigger IBD flares and exacerbations","All fiber during remission","Exercise"],1,"NSAIDs can worsen IBD through prostaglandin inhibition and direct mucosal injury. Acetaminophen is preferred for pain management. During flares: low-fiber diet may reduce symptoms. During remission: balanced diet with gradual fiber reintroduction. Smoking cessation is important (especially for Crohn's)."),
  rpn("REX-PN","Pharmacology",2,"A client prescribed an antibiotic for a suspected bacterial infection should understand that antibiotics:",["Treat viral infections effectively","Are effective only against bacterial infections and should not be used for viral illnesses like the common cold","Can be shared with family members who have similar symptoms","Should be stopped when symptoms improve"],1,"Antibiotic stewardship: antibiotics treat bacterial infections only (ineffective against viruses). Complete the prescribed course. Do not share medications. Report side effects (diarrhea may indicate C. diff). Misuse contributes to antibiotic resistance, a global health threat."),
  rpn("REX-PN","Mental Health",2,"A client with depression who has not improved after 4 weeks on an SSRI should:",["Stop all medications immediately","Continue the medication as antidepressants typically require 4-6 weeks for full therapeutic effect, but communicate concerns to the prescriber","Switch to a different antidepressant without consulting the prescriber","Take double the dose"],1,"Antidepressant response: 2-4 weeks for initial improvement, 6-12 weeks for full effect. At 4 weeks: partial response warrants continued treatment. No response at 4-6 weeks: reassess diagnosis, consider dose increase or switch. NEVER stop SSRIs abruptly (withdrawal syndrome: dizziness, nausea, brain zaps)."),
  rpn("REX-PN","Pediatrics",2,"The nurse should teach parents that a child with an ear infection should be positioned:",["On the affected ear to promote drainage","With the affected ear facing up or in a comfortable position, depending on the type of infection","Face down","In Trendelenburg position"],1,"Positioning depends on infection type: otitis media (middle ear): no specific position required, comfort positioning. If tympanic membrane has ruptured: affected ear down to promote drainage. Otitis externa: affected ear up to keep the canal open for drops. Warm compress to affected ear provides comfort."),
  rpn("REX-PN","Fundamentals",2,"When documenting in the client's medical record, the nurse should:",["Use white-out to correct mistakes","Draw a single line through errors, write 'error' and initials, then document the correct information","Erase or obliterate incorrect entries","Leave blank spaces for later completion"],1,"Documentation corrections: single line through error (so original entry remains readable), write 'error' or 'mistaken entry,' date, time, and initial. Then document correct information. Late entries: label as 'late entry' with current date/time. Never alter records (legal document, evidence in court)."),
  rpn("REX-PN","Musculoskeletal",3,"A client in skeletal traction should have pin care performed to:",["Remove the pins daily for cleaning","Clean pin sites per facility protocol to prevent osteomyelitis","Leave the pins undisturbed without any care","Cover the pins completely with gauze"],1,"Skeletal traction pin care: clean pin sites per facility protocol (usually daily or BID with normal saline or chlorhexidine). Assess for signs of pin site infection (redness, drainage, warmth, loosening). Do not remove crusts (they seal the site). Report purulent drainage, increased pain, or pin loosening."),
  rpn("REX-PN","Renal",2,"A client on hemodialysis should be taught to protect their arteriovenous fistula by:",["Wearing tight sleeves to support the fistula","Avoiding blood pressure measurements, blood draws, and IV insertions on the fistula arm","Using the fistula arm for all procedures","Applying tight tourniquets daily to the fistula arm"],1,"AV fistula protection: no BP cuffs, blood draws, IV starts, or tight clothing on the fistula arm. Assess thrill (palpable vibration) and bruit (audible whoosh) daily. Elevate after creation. Report: loss of thrill/bruit (thrombosis), pain, swelling, excessive bleeding. Fistula is the lifeline for dialysis."),
  rpn("REX-PN","Maternal/Newborn",2,"During the postpartum assessment, the nurse should evaluate the fundus position. Immediately after delivery, the fundus should be:",["At the xiphoid process","At or slightly below the umbilicus, firm and midline","Not palpable","Well above the umbilicus"],1,"Immediately postpartum: fundus at or slightly below the umbilicus, firm and midline. Involution: descends approximately 1 fingerbreadth (1 cm) per day. By day 10: no longer palpable above the symphysis pubis. Boggy fundus = uterine atony (massage fundus, assess for hemorrhage)."),
  rpn("REX-PN","Infection Control",2,"Contact precautions require the nurse to wear:",["Only a mask","Gown and gloves upon entering the client's room","Full face shield and N95 respirator","No additional PPE beyond standard precautions"],1,"Contact precautions: gown and gloves upon room entry, regardless of planned care activities. Dedicated equipment (stethoscope, BP cuff). Remove PPE before leaving the room. Hand hygiene after PPE removal. For MRSA, VRE, and C. diff. Patient should not leave the room unless necessary."),
  rpn("REX-PN","Hematological",2,"A client prescribed enoxaparin should be taught to report which symptom immediately?",["Mild bruising at the injection site","Unusual bleeding, blood in urine or stool, or prolonged bleeding from cuts","Mild pain at the injection site","Slight redness at the injection site"],1,"Enoxaparin (anticoagulant) bleeding signs requiring immediate reporting: hematuria, melena/hematochezia, hematemesis, hemoptysis, prolonged bleeding from cuts, unusual bruising, severe headache (intracranial bleeding), and dizziness/weakness (internal bleeding). Protamine sulfate is the partial reversal agent."),
  rpn("REX-PN","Integumentary",2,"A client with diabetes should be taught that wound healing may be delayed because:",["Diabetes has no effect on wound healing","Elevated blood glucose levels impair immune function, circulation, and tissue oxygenation","Only insulin-dependent diabetes affects healing","Wound healing is faster with diabetes"],1,"Diabetic wound healing impairment: hyperglycemia impairs WBC function (phagocytosis), reduces peripheral circulation (atherosclerosis, microvascular disease), decreases tissue oxygenation, and promotes infection. Strict glucose control, nutrition optimization, and professional wound management improve outcomes."),
  rpn("REX-PN","Emergency",2,"When managing a client who has fainted (vasovagal syncope), the nurse should:",["Elevate the head of the bed","Lay the client flat, elevate the legs, ensure airway patency, and monitor vital signs","Apply cold water to the face immediately","Administer smelling salts"],1,"Vasovagal syncope management: lay flat (increases cerebral blood flow), elevate legs (promotes venous return), ensure airway patency, monitor vital signs, and assess for injuries from the fall. Once alert, sit up slowly. Evaluate for contributing factors (dehydration, medications, pain, emotions)."),
  rpn("REX-PN","Oncology",2,"A client with cancer fatigue should be counseled that the most effective intervention is:",["Complete bed rest","Regular moderate exercise such as walking (most effective evidence-based intervention for cancer-related fatigue)","Increased caffeine intake","Energy supplements"],1,"Cancer-related fatigue: regular moderate exercise is the most effective intervention (strong evidence). Walking 20-30 minutes most days improves fatigue, sleep quality, and mood. Other interventions: energy conservation, sleep hygiene, CBT, optimal nutrition, and treatment of contributing factors (anemia, pain, depression)."),
  rpn("REX-PN","Safety",2,"When caring for a client with a seizure disorder, the nurse should have which safety equipment at the bedside?",["Only a tongue blade","Suction equipment, oxygen, padded side rails, and oral airway","Physical restraints","Intravenous sedatives"],1,"Seizure precautions bedside equipment: suction equipment (for airway clearance post-seizure), oxygen, padded side rails (injury prevention), oral airway (for post-seizure use ONLY, never during a seizure), and IV access. Time seizure, note characteristics, and maintain safety during and after the event."),
  rpn("REX-PN","Geriatrics",2,"A confused elderly client who wanders should have which safety intervention?",["Physical restraints to prevent movement","Environmental modifications, identification bracelet, and supervised activities","Sedating medications to prevent walking","Locked room confinement"],1,"Wandering management: identification bracelet (with name, contact info), locked/secured exits with alarm systems, supervised activities, maintain familiar environment, consistent routine, adequate lighting, and address underlying causes (pain, hunger, toileting needs). Avoid restraints (increase agitation, injury, and mortality)."),
  rpn("REX-PN","Ethics/Legal",2,"Documentation should be completed:",["At the end of the shift for all activities","As soon as possible after care is provided (timely documentation)","Only when there is free time","Only for unusual events"],1,"Timely documentation: record as close to the time of care as possible (prevents omissions and inaccuracies). Document before, during (flow sheets), and after interventions. Late entries are labeled as such. If an event is not documented, it is legally considered not done. Complete, accurate, and objective."),
  rpn("REX-PN","Delegation",2,"When delegating to UAP, the nurse must ensure the task is:",["Beyond the UAP's training level to promote learning","Within the UAP's scope of practice, the client's condition is stable, and proper supervision is available","Anything the nurse does not want to do","A complex assessment task"],1,"Five Rights of Delegation: Right task (routine, predictable outcome), Right circumstance (stable client, predictable environment), Right person (competent, trained UAP), Right direction/communication (clear, concise instructions), Right supervision (monitor, evaluate, provide feedback)."),
  rpn("REX-PN","Community Health",2,"A client being discharged with a new medication should receive teaching that includes:",["Verbal instructions only","Written and verbal instructions about medication name, purpose, dose, frequency, side effects, and follow-up","Only the medication name and dose","A pamphlet without verbal explanation"],1,"Effective discharge medication teaching: combine verbal explanation with written materials (improves retention), use teach-back method (client repeats information in own words), assess health literacy, use plain language, include: name, purpose, dose, timing, side effects to report, and follow-up plan."),
  rpn("REX-PN","Health Promotion",2,"The nurse should teach clients that the recommended amount of physical activity for adults is:",["30 minutes per week","At least 150 minutes per week of moderate-intensity aerobic activity","Only strength training 5 days per week","No specific recommendation exists"],1,"WHO/CDC recommendation: >= 150 min/week moderate-intensity aerobic (brisk walking, cycling) OR >= 75 min/week vigorous-intensity aerobic, PLUS muscle-strengthening activities >= 2 days/week. Additional health benefits with > 300 min/week moderate activity. Any movement is better than none."),
];

async function main() {
  let inserted = 0;
  const batchSize = 50;
  for (let i = 0; i < QS.length; i += batchSize) {
    const batch = QS.slice(i, i + batchSize);
    const values: string[] = [];
    const params: any[] = [];
    let idx = 1;
    for (const q of batch) {
      values.push(`($${idx},$${idx+1},$${idx+2},$${idx+3},$${idx+4},$${idx+5}::jsonb,$${idx+6}::jsonb,$${idx+7},$${idx+8}::integer,$${idx+9},$${idx+10},$${idx+11})`);
      params.push(q.tier,q.exam,"multiple_choice","published",q.stem,JSON.stringify(q.options),JSON.stringify([q.correct]),q.rationale,q.diff,q.bs,"BOTH",hash(q.stem));
      idx += 12;
    }
    const sql = `INSERT INTO exam_questions (tier, exam, question_type, status, stem, options, correct_answer, rationale, difficulty, body_system, region_scope, stem_hash)
                 SELECT v.* FROM (VALUES ${values.join(",")}) AS v(tier,exam,question_type,status,stem,options,correct_answer,rationale,difficulty,body_system,region_scope,stem_hash)
                 WHERE NOT EXISTS (SELECT 1 FROM exam_questions e WHERE e.stem_hash = v.stem_hash)`;
    const result = await pool.query(sql, params);
    inserted += result.rowCount || 0;
  }
  console.log(`[Combined-B4] Inserted ${inserted}/${QS.length}`);
  const counts = await pool.query(`SELECT tier, count(*) as cnt FROM exam_questions WHERE status='published' GROUP BY tier ORDER BY tier`);
  counts.rows.forEach((r: any) => console.log(`  ${r.tier}: ${r.cnt}`));
  await pool.end();
}
main().catch(e => { console.error(e); process.exit(1); });
